#include <stdio.h>
void testAuto() {
    int x = 5;  // auto is default for local
    printf("Before: x = %d\n", x);
    x++;
    printf("After increment: x = %d\n", x);
}

int main() {
    printf("First call:\n");
    testAuto();
    printf("Second call:\n");
    testAuto();
    return 0;
}
// Output:
// First call:
// Before: x = 5
// After increment: x = 6
// Second call:
// Before: x = 5
// After increment: x = 6

#include <stdio.h>
void counter() {
    static int count = 0;  // initialized only once
    count++;
    printf("Count = %d\n", count);
}

int main() {
    counter();  // prints 1
    counter();  // prints 2
    counter();  // prints 3
    counter();  // prints 4
    return 0;
}
// Output:
// Count = 1
// Count = 2
// Count = 3
// Count = 4

/* File1.c */
#include <stdio.h>
extern int globalVar;  // declaration

void modify() {
    globalVar += 10;
    printf("In modify(): globalVar = %d\n", globalVar);
}

/* File2.c */
int globalVar = 50;  // definition

int main() {
    printf("Initial: globalVar = %d\n", globalVar);
    modify();
    printf("After modify(): globalVar = %d\n", globalVar);
    return 0;
}
// Output:
// Initial: globalVar = 50
// In modify(): globalVar = 60
// After modify(): globalVar = 60

#include <stdio.h>
int main() {
    register int i;
    int sum = 0;

    // Using register for loop counter (faster access)
    for (i = 1; i <= 100; i++) {
        sum += i;
    }

    printf("Sum = %d\n", sum);

    // Following would cause compile error:
    // printf("%p\n", &i);  // ERROR: cannot take address of register variable

    return 0;
}
// Output: Sum = 5050
